+/**
+ * Save autopilot state.
+ */
+function saveAutopilotState(state) {
+  try {
+    writeFileSync(AUTOPILOT_STATE_PATH, JSON.stringify(state, null, 2), 'utf-8');
+  } catch { /* best effort */ }
+}
